var intersection = function(nums) {
    const cnt = new Map();
    for (const arr of nums) {
        for (const v of arr) cnt.set(v, (cnt.get(v) || 0) + 1);
    }
    const k = nums.length;
    const res = [];
    for (const [v, c] of cnt) if (c === k) res.push(v);
    res.sort((a, b) => a - b);
    return res;
};
